INSERT INTO api_review (id, order_id, api_id, user_id, rating, content, reply, reply_time, parent_id, reply_type, create_time) VALUES
(1, 1, 1, 33, 5.0, '识别准确率很高，响应速度快，非常满意！', '感谢您的支持，我们会继续优化服务！', '2026-01-16 09:00:00', NULL, 0, '2026-01-15 16:30:00'),
(2, 2, 2, 34, 4.5, '分类效果不错，但有些边界情况处理不够好。', '感谢反馈，我们会持续改进边界情况的处理。', '2026-01-17 10:00:00', NULL, 0, '2026-01-16 17:30:00'),
(3, 3, 7, 35, 5.0, '情感分析非常准确，API文档也很详细，推荐！', '谢谢您的认可，欢迎继续使用！', '2026-01-18 09:00:00', NULL, 0, '2026-01-17 15:30:00'),
(4, 4, 8, 36, 4.0, '关键词提取效果还可以，希望能支持更多语言。', '感谢建议，我们计划在下个版本支持更多语言。', '2026-01-19 10:00:00', NULL, 0, '2026-01-18 16:30:00'),
